@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase small fw-bold">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="me-2">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    width: 220px;
    min-height: 100%;
    border-right: 1px solid #dee2e6;
    padding-top: 1rem;
    background: #f8f9fa;
}

.settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0;
    padding: 0.6rem 1rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="Toggle" style="cursor: pointer;">
        <span>🔑 Change Password</span>
        <span class="small text-muted">@(IsExpanded ? "▲" : "▼")</span>
    </div>

    @if (IsExpanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded { get; set; }
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    private void Toggle() => IsExpanded = !IsExpanded;

    private async Task UpdatePassword()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "All password fields are required.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully.";
            _isError = false;
            _currentPassword = _newPassword = _confirmPassword = "";
        }
        catch
        {
            _message = "Failed to update password.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings

@if (Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Device</strong> from <strong>@Location</strong>?</p>
                    <p class="text-muted small">This will immediately sign out that device.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings
@using sv_740d78081e09491c8b0700b2d326d74f.Models

<div class="card mb-3">
    <div class="card-header">📱 Active Sessions</div>
    <div class="card-body p-0">
        <table class="table table-hover mb-0">
            <thead class="table-light">
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td>
                            @if (session.Id == CurrentSessionId)
                            {
                                <span class="badge bg-success">Current</span>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => RequestRevoke(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

<RevokeSessionDialog Visible="_showDialog"
                     Device="@_pendingSession?.Device"
                     Location="@_pendingSession?.Location"
                     OnConfirm="ConfirmRevoke"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private bool _showDialog;
    private ActiveSession? _pendingSession;

    private void RequestRevoke(ActiveSession session)
    {
        _pendingSession = session;
        _showDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_pendingSession is not null)
        {
            await OnRevoke.InvokeAsync(_pendingSession.Id);
        }
        _showDialog = false;
        _pendingSession = null;
    }

    private void CancelRevoke()
    {
        _showDialog = false;
        _pendingSession = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

