@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings
@using sv_740d78081e09491c8b0700b2d326d74f.Models
@using sv_740d78081e09491c8b0700b2d326d74f.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    @if (_message is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="mb-3">
                <label class="form-label d-block">Avatar Preview</label>
                <img src="@_avatarUrl" alt="Avatar" class="rounded-circle mb-2"
                     style="width: 120px; height: 120px; object-fit: cover; border: 3px solid #dee2e6;" />
                <div class="small text-muted text-break">@_avatarUrl</div>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
}

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _message = "Profile saved successfully!";
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = null;
    }
}

@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings
@using sv_740d78081e09491c8b0700b2d326d74f.Models
@using sv_740d78081e09491c8b0700b2d326d74f.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading notification preferences…</p>
}
else
{
    @if (_message is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="card mb-3">
        <div class="card-header">Notification Toggles</div>
        <div class="card-body">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header">Channel Muting</div>
        <div class="card-body">
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        <span class="badge bg-secondary me-1">#</span>@channel
                        @if (isMuted)
                        {
                            <span class="badge bg-warning ms-1">Muted</span>
                        }
                    </label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private static readonly List<string> _allChannels =
        ["general", "engineering", "marketing", "design", "random", "announcements"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications, _pushNotifications, _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings
@using sv_740d78081e09491c8b0700b2d326d74f.Models
@using sv_740d78081e09491c8b0700b2d326d74f.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-3">
        <div class="card-header">🛡️ Two-Factor Authentication</div>
        <div class="card-body d-flex align-items-center justify-content-between">
            <div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="ToggleTwoFactor" />
                    <label class="form-check-label" for="twoFactor">
                        Enable Two-Factor Authentication
                    </label>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <small class="text-muted d-block mt-1">
                        Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </small>
                }
            </div>
            <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary") fs-6">
                @(_twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
    </div>

    <ActiveSessionsTable Sessions="_sessions" OnRevoke="HandleRevoke" />
}

@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private void ToggleTwoFactor(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)(e.Value ?? false);
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevoke(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings
@using sv_740d78081e09491c8b0700b2d326d74f.Models
@using sv_740d78081e09491c8b0700b2d326d74f.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_message is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-3">
                <div class="card-header">Theme</div>
                <div class="card-body">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
