{"file_text": "@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings
@using sv_740d78081e09491c8b0700b2d326d74f.Models
@using sv_740d78081e09491c8b0700b2d326d74f.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_message is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-3">
                <div class="card-header">Theme</div>
                <div class="card-body">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header">Font Size</div>
                <div class="card-body">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"size-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"size-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header">Language</div>
                <div class="card-body">
                    <select class="form-select" @bind="_language">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                    </select>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header">Compact Mode</div>
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Enable compact layout</label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-5">
            <div class="card">
                <div class="card-header">👁️ Live Preview</div>
                <div class="card-body @PreviewBackgroundClass" style="@PreviewStyle min-height: 200px; transition: all 0.2s ease;">
                    <h5 class="@PreviewTextClass">Sample Heading</h5>
                    <p class="@PreviewTextClass" style="@PreviewFontStyle">
                        This is how your content will look with the selected settings.
                        The theme is <strong>@_theme</strong>, font size is <strong>@_fontSize</strong>,
                        and language is <strong>@_language</strong>.
                    </p>
                    <div class="d-flex gap-2 @(_compactMode ? "mt-1" : "mt-3")">
                        <button class="btn @PreviewButtonClass @(_compactMode ? "btn-sm" : "")">Action</button>
                        <button class="btn btn-outline-secondary @(_compactMode ? "btn-sm" : "")">Cancel</button>
                    </div>
                    @if (!_compactMode)
                    {
                        <hr />
                        <p class="@PreviewTextClass small">Additional content is visible in normal layout mode.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewBackgroundClass => _theme switch
    {
        "Dark" => "bg-dark",
        _ => "bg-light"
    };

    private string PreviewTextClass => _theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewButtonClass => _theme switch
    {
        "Dark" => "btn-light",
        _ => "btn-primary"
    };

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}
