@page "/settings"
@namespace sv_740d78081e09491c8b0700b2d326d74f.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />

    <div class="settings-content p-4">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
